import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ChevronLeft, ChevronRight, User, Trash2, X, Save, CreditCard, Lock, Calendar, Hash } from 'lucide-react';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]); 
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [itemParaEditar, setItemParaEditar] = useState(null);
  const [filtroData, setFiltroData] = useState({
    mes: new Date().getMonth(),
    ano: new Date().getFullYear()
  });

  const mesesNominais = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  const formasPagamento = [
    "Boleto",
    "Crédito",
    "Débito",
    "Dinheiro",
    "Pix",
    "Transferência"
  ].sort();

  useEffect(() => {
    carregarDadosIniciais();
  }, [filtroData]);

  async function carregarDadosIniciais() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data: meuPerfil } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', user.id)
      .single();
    
    setPerfilLogado(meuPerfil);

    if (meuPerfil?.tipo_usuario === 'proprietario') {
      const { data: dCartoes } = await supabase.from('cartoes').select('id, nome').order('nome');
      const { data: dUsers } = await supabase.from('profiles').select('id, nome').order('nome');
      setCartoes(dCartoes || []);
      setUsuarios(dUsers || []);
    }

    fetchDespesas(meuPerfil);
  }

  async function fetchDespesas(perfil) {
    let query = supabase.from('compras').select('*, profiles(nome)').order('data_compra', { ascending: false });

    if (perfil?.tipo_usuario !== 'proprietario') {
      query = query.eq('user_id', perfil.id);
    }

    const { data, error } = await query;

    if (!error && data) {
      const projetadas = [];
      data.forEach(item => {
        const numParcelas = item.num_parcelas || 1;
        for (let i = 0; i < numParcelas; i++) {
          const [ano, mes, dia] = item.data_compra.split('-');
          const dataCompra = new Date(ano, mes - 1, dia);
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela.getMonth() === filtroData.mes && dataParcela.getFullYear() === filtroData.ano) {
            projetadas.push({
              ...item,
              parcelaAtual: i + 1,
              valorParcela: parseFloat(item.valor_total) / numParcelas,
              nomeResponsavel: item.profiles?.nome || '⚠️ Pendente'
            });
          }
        }
      });
      setDespesas(projetadas);
    }
  }

  const handleUpdate = async (e) => {
    e.preventDefault();
    if (perfilLogado?.tipo_usuario !== 'proprietario') return;

    const isCredito = itemParaEditar.forma_pagamento === 'Crédito';
    const numParcelasFinal = isCredito ? parseInt(itemParaEditar.num_parcelas) : 1;

    const { error } = await supabase
      .from('compras')
      .update({
        descricao: itemParaEditar.descricao,
        loja: itemParaEditar.loja,
        user_id: itemParaEditar.user_id, 
        valor_total: parseFloat(itemParaEditar.valor_total),
        pedido: itemParaEditar.pedido,
        nota_fiscal: itemParaEditar.nota_fiscal,
        forma_pagamento: itemParaEditar.forma_pagamento,
        cartao: isCredito ? itemParaEditar.cartao : 'À Vista',
        data_compra: itemParaEditar.data_compra,
        num_parcelas: numParcelasFinal,
        parcelado: numParcelasFinal > 1
      })
      .eq('id', itemParaEditar.id);

    if (error) alert("Erro ao atualizar: " + error.message);
    else {
      setItemParaEditar(null);
      fetchDespesas(perfilLogado);
    }
  };

  const handleDelete = async (id) => {
    if (perfilLogado?.tipo_usuario !== 'proprietario') return;
    
    if (window.confirm("Deseja excluir esta despesa permanentemente?")) {
      const { error } = await supabase.from('compras').delete().eq('id', id);
      if (!error) {
        setItemParaEditar(null);
        fetchDespesas(perfilLogado);
      }
    }
  };

  const mudarMes = (direcao) => {
    let novoMes = filtroData.mes + direcao;
    let novoAno = filtroData.ano;
    if (novoMes < 0) { novoMes = 11; novoAno--; }
    else if (novoMes > 11) { novoMes = 0; novoAno++; }
    setFiltroData({ mes: novoMes, ano: novoAno });
  };

  const labelStyle = { fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block', textTransform: 'uppercase' };

  return (
    <div className="fade-in" style={{ paddingBottom: '50px' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '30px' }}>
        <div>
          <h2 style={{ fontSize: '1.8rem', fontWeight: 800, color: '#0f172a', margin: 0 }}>Extrato de Gastos</h2>
          <p style={{ color: '#64748b', margin: '5px 0 0 0' }}>
            {perfilLogado?.tipo_usuario === 'proprietario' ? 'Gerencie todos os lançamentos da unidade' : 'Veja seus gastos pessoais'}
          </p>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '15px', background: 'white', padding: '10px 15px', borderRadius: '16px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
          <button onClick={() => mudarMes(-1)} style={navBtnStyle}><ChevronLeft size={20} /></button>
          <div style={{ textAlign: 'center', minWidth: '110px' }}>
            <span style={{ display: 'block', fontWeight: 800, fontSize: '0.9rem', color: '#0f172a' }}>{mesesNominais[filtroData.mes]}</span>
            <span style={{ color: '#94a3b8', fontSize: '0.75rem', fontWeight: 600 }}>{filtroData.ano}</span>
          </div>
          <button onClick={() => mudarMes(1)} style={navBtnStyle}><ChevronRight size={20} /></button>
        </div>
      </div>

      <div className="card" style={{ padding: '0', overflowX: 'auto', borderRadius: '20px', border: '1px solid #f1f5f9' }}>
        <table style={{ minWidth: '1000px', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ textAlign: 'left', background: '#f8fafc' }}>
              <th style={thStyle}>Data</th>
              <th style={thStyle}>Responsável</th>
              <th style={thStyle}>Descrição</th>
              <th style={thStyle}>Loja</th>
              <th style={thStyle}>Cartão</th>
              <th style={thStyle}>Parcela</th>
              <th style={{ ...thStyle, textAlign: 'right' }}>Valor Parcela</th>
            </tr>
          </thead>
          <tbody>
            {despesas.length === 0 ? (
                <tr><td colSpan="7" style={{ textAlign: 'center', padding: '40px', color: '#94a3b8' }}>Nenhum gasto encontrado para este período.</td></tr>
            ) : (
                despesas.map((item, idx) => (
                <tr 
                    key={`${item.id}-${idx}`} 
                    className={perfilLogado?.tipo_usuario === 'proprietario' ? 'clickable-row' : ''} 
                    onClick={() => perfilLogado?.tipo_usuario === 'proprietario' && setItemParaEditar(item)}
                    style={{ borderBottom: '1px solid #f1f5f9', cursor: perfilLogado?.tipo_usuario === 'proprietario' ? 'pointer' : 'default' }}
                >
                    <td style={tdStyle}>{item.data_compra.split('-').reverse().slice(0,2).join('/')}</td>
                    <td style={{ ...tdStyle, fontWeight: '700', color: item.profiles?.nome ? '#4361ee' : '#f43f5e' }}>
                      {item.nomeResponsavel}
                    </td>
                    <td style={{ ...tdStyle, fontWeight: '500', color: '#1e293b' }}>{item.descricao}</td>
                    <td style={tdStyle}>{item.loja || '-'}</td>
                    <td style={tdStyle}>{item.cartao || 'À Vista'}</td>
                    <td style={tdStyle}>
                    <span style={{ 
                        background: item.parcelado ? '#eef2ff' : '#f0fdf4', 
                        color: item.parcelado ? '#4361ee' : '#16a34a', 
                        padding: '4px 10px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: '800' 
                    }}>
                        {item.parcelado ? `${item.parcelaAtual}/${item.num_parcelas}` : 'À Vista'}
                    </span>
                    </td>
                    <td style={{ ...tdStyle, fontWeight: '800', textAlign: 'right', color: '#0f172a' }}>
                    R$ {item.valorParcela.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </td>
                </tr>
                ))
            )}
          </tbody>
        </table>
      </div>

      {itemParaEditar && (
        <div className="modal-overlay" style={modalOverlayStyle}>
          <div className="modal-content" style={{ maxWidth: '550px', borderRadius: '28px', padding: '30px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
              <h3 style={{ margin: 0, fontWeight: 800 }}>Editar Lançamento</h3>
              <button onClick={() => setItemParaEditar(null)} style={closeBtnStyle}><X /></button>
            </div>

            <form onSubmit={handleUpdate} style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
              
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label style={labelStyle}>Data da Compra</label>
                  <input type="date" className="form-control" value={itemParaEditar.data_compra || ''} onChange={e => setItemParaEditar({...itemParaEditar, data_compra: e.target.value})} required />
                </div>
                <div>
                  <label style={labelStyle}>Responsável</label>
                  <select className="form-control" value={itemParaEditar.user_id || ''} onChange={e => setItemParaEditar({...itemParaEditar, user_id: e.target.value})} style={{ fontWeight: '600' }} required>
                    <option value="">Vincular Usuário...</option>
                    {usuarios.map(u => (<option key={u.id} value={u.id}>{u.nome}</option>))}
                  </select>
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label style={labelStyle}>Forma de Pagamento</label>
                  <select className="form-control" value={itemParaEditar.forma_pagamento || 'Crédito'} onChange={e => setItemParaEditar({...itemParaEditar, forma_pagamento: e.target.value})}>
                    {formasPagamento.map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                </div>
                
                {itemParaEditar.forma_pagamento === 'Crédito' ? (
                  <div>
                    <label style={labelStyle}>Cartão</label>
                    <select className="form-control" value={itemParaEditar.cartao || ''} onChange={e => setItemParaEditar({...itemParaEditar, cartao: e.target.value})}>
                      <option value="">Selecione...</option>
                      {cartoes.map(c => (<option key={c.id} value={c.nome}>{c.nome}</option>))}
                    </select>
                  </div>
                ) : (
                  <div>
                    <label style={labelStyle}>Status</label>
                    <div style={{ padding: '10px', background: '#f8fafc', borderRadius: '10px', fontSize: '0.8rem', fontWeight: '700', color: '#64748b', border: '1px solid #e2e8f0', height: '42px', display: 'flex', alignItems: 'center' }}>
                      Pagamento à Vista
                    </div>
                  </div>
                )}
              </div>

              <div>
                <label style={labelStyle}>Descrição</label>
                <input className="form-control" value={itemParaEditar.descricao || ''} onChange={e => setItemParaEditar({...itemParaEditar, descricao: e.target.value})} required />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label style={labelStyle}>Loja</label>
                  <input className="form-control" value={itemParaEditar.loja || ''} onChange={e => setItemParaEditar({...itemParaEditar, loja: e.target.value})} />
                </div>
                <div>
                  <label style={labelStyle}>Valor Total (Compra)</label>
                  <input type="number" step="0.01" className="form-control" value={itemParaEditar.valor_total || ''} onChange={e => setItemParaEditar({...itemParaEditar, valor_total: e.target.value})} required />
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label style={labelStyle}>N° de Parcelas</label>
                  <input 
                    type="number" 
                    min="1" 
                    disabled={itemParaEditar.forma_pagamento !== 'Crédito'}
                    className="form-control" 
                    value={itemParaEditar.forma_pagamento === 'Crédito' ? (itemParaEditar.num_parcelas || 1) : 1} 
                    onChange={e => setItemParaEditar({...itemParaEditar, num_parcelas: e.target.value})} 
                    required 
                  />
                </div>
                <div>
                  <label style={labelStyle}>N° Pedido</label>
                  <input className="form-control" value={itemParaEditar.pedido || ''} onChange={e => setItemParaEditar({...itemParaEditar, pedido: e.target.value})} />
                </div>
              </div>

              <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
                <button type="submit" className="btn-primary" style={{ flex: 2, height: '50px', borderRadius: '14px', fontWeight: '700' }}>
                  <Save size={18} style={{ marginRight: '8px' }} /> Atualizar
                </button>
                <button type="button" onClick={() => handleDelete(itemParaEditar.id)} style={{ flex: 1, background: '#fff1f2', color: '#f43f5e', border: 'none', borderRadius: '14px', cursor: 'pointer', fontWeight: '700' }}>
                  <Trash2 size={20} />
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const thStyle = { padding: '15px 20px', fontSize: '0.75rem', color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: '800' };
const tdStyle = { padding: '18px 20px', fontSize: '0.9rem', color: '#475569' };
const navBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', color: '#4361ee', display: 'flex', alignItems: 'center' };
const modalOverlayStyle = { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(15, 23, 42, 0.5)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 };
const closeBtnStyle = { border: 'none', background: '#f1f5f9', color: '#64748b', borderRadius: '8px', cursor: 'pointer', width: '32px', height: '32px', display: 'flex', alignItems: 'center', justifyContent: 'center' };

export default Listagem;
